// Pull both ensures-`forall`s into the proof context so their triggers
// fire on `post1_self_.page_array@[i]` and `post2_self_.page_array@[i]`.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// At the modified index, every field of the Page is forced equal between
// post1 and post2 (each matches the corresponding field of pre_self_,
// and `owning_container` matches `owning_container_op` in both runs).
assert(post1_self_.page_array@[index as int].addr =~= post2_self_.page_array@[index as int].addr);
assert(post1_self_.page_array@[index as int].state =~= post2_self_.page_array@[index as int].state);
assert(post1_self_.page_array@[index as int].is_io_page =~= post2_self_.page_array@[index as int].is_io_page);
assert(post1_self_.page_array@[index as int].rev_pointer =~= post2_self_.page_array@[index as int].rev_pointer);
assert(post1_self_.page_array@[index as int].ref_count =~= post2_self_.page_array@[index as int].ref_count);
assert(post1_self_.page_array@[index as int].owning_container =~= post2_self_.page_array@[index as int].owning_container);
assert(post1_self_.page_array@[index as int].mappings =~= post2_self_.page_array@[index as int].mappings);
assert(post1_self_.page_array@[index as int].io_mappings =~= post2_self_.page_array@[index as int].io_mappings);
assert(post1_self_.page_array@[index as int] =~= post2_self_.page_array@[index as int]);

// Pointwise: for every i in [0, NUM_PAGES), post1 and post2 agree.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // Closed by the field-wise + struct extensionality asserts above.
    } else {
        // Both =~= pre_self_.page_array@[i] by the two foralls above.
    }
}

// Sequence extensionality lifts the pointwise equality to view equality.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
